using System.Text;
using System.Text.RegularExpressions;
using SkiaSharp;

Regex blankTextRegex = new(">\\s+</text>", RegexOptions.Compiled);
Regex blankAttrRegex = new("<text[^>]*x=\"\"[^>]*y=\"\"[^>]*>\\s*</text>", RegexOptions.Compiled | RegexOptions.Singleline);

const int parallelTasks = 5;
const int textElementsPerTask = 100;
const int rounds = 100;

bool RenderAndCheck(int taskIndex)
{
    using var svgStream = new MemoryStream();
    using (var canvas = SKSvgCanvas.Create(new SKRect(0, 0, 500, 500), svgStream))
    {
        for (int i = 0; i < textElementsPerTask; i++)
        {
            using var paint = new SKPaint
            {
                Color = SKColors.Black,
                IsAntialias = true,
                TextSize = 14,
            };
            using var typeface = SKTypeface.FromFamilyName("Arial") ?? SKTypeface.Default;
            using var font = new SKFont(typeface, 14);
            var text = $"Hello, World {i + 1} of {textElementsPerTask}!";
            canvas.DrawText(text, 10, i * 15 + 20, SKTextAlign.Left, font, paint);
        }
    }

    var svgString = Encoding.UTF8.GetString(svgStream.ToArray());
    var containsBlankText = blankTextRegex.IsMatch(svgString);
    var containsBlankAttrs = blankAttrRegex.IsMatch(svgString);

    if (containsBlankText || containsBlankAttrs)
    {
        Console.WriteLine($"BUG task={taskIndex} blankText={containsBlankText} blankAttrs={containsBlankAttrs}");
        return true;
    }

    return false;
}

int bugHits = 0;
for (int round = 1; round <= rounds; round++)
{
    var results = await Task.WhenAll(Enumerable.Range(0, parallelTasks).Select(i => Task.Run(() => RenderAndCheck(i))));
    if (results.Any(r => r))
    {
        bugHits++;
    }

    if (round % 10 == 0)
    {
        Console.WriteLine($"Round {round}/{rounds} complete. bugHits={bugHits}");
    }
}

Console.WriteLine($"FINAL bugHits={bugHits} over rounds={rounds}");
